/**
 * DAN-2193: Enrichment batch 46 — final batch (13 remaining pages)
 */

import { PrismaClient } from '@prisma/client'
import dotenv from 'dotenv'
import { fileURLToPath } from 'url'
import { dirname, join } from 'path'
const __dirname = dirname(fileURLToPath(import.meta.url))
dotenv.config({ path: join(__dirname, '../../.env.local') })

const prisma = new PrismaClient()

async function enrichPage(slug, analysis, citations, faqs) {
  const comparison = await prisma.comparison.findUnique({ where: { slug } })
  if (!comparison) { console.log(`⚠️  Not found: ${slug}`); return }
  const existingContent = comparison.content
  const hasEnrichment = existingContent && typeof existingContent === 'object' && !Array.isArray(existingContent) &&
    ('analysis' in existingContent || 'expertAnalysis' in existingContent || 'enrichedAt' in existingContent)
  if (hasEnrichment) { console.log(`✅ Already enriched: ${slug}`); return }
  const baseContent = Array.isArray(existingContent) ? {} : (existingContent && typeof existingContent === 'object' ? existingContent : {})
  await prisma.comparison.update({
    where: { slug },
    data: { content: { ...baseContent, analysis, citations, enrichedAt: new Date().toISOString() } },
  })
  await prisma.fAQ.deleteMany({ where: { comparisonId: comparison.id } })
  for (const faq of faqs) {
    await prisma.fAQ.create({ data: { comparisonId: comparison.id, question: faq.question, answer: faq.answer } })
  }
  console.log(`✨ Enriched: ${slug}`)
}

